/*
Emitted when the size of the viewport is changed, whether by resizing of window, or some other means.
*/
func (self Instance) OnSizeChanged(cb func(), flags ...Signal.Flags) {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	self[0].AsObject()[0].Connect(gd.NewStringName("size_changed"), gd.NewCallable(cb), int64(flags_together))
}

func (self class) SizeChanged() Signal.Any {
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`size_changed`))))
}

/*
Emitted when a Control node grabs keyboard focus.

Note: A Control node losing focus doesn't cause this signal to be emitted.
*/
func (self Instance) OnGuiFocusChanged(cb func(node Control.Instance), flags ...Signal.Flags) {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	self[0].AsObject()[0].Connect(gd.NewStringName("gui_focus_changed"), gd.NewCallable(cb), int64(flags_together))
}

func (self class) GuiFocusChanged() Signal.Any {
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`gui_focus_changed`))))
}

func (self class) AsViewport() Advanced          { return Advanced{pointers.AsA[gdclass.Viewport](self[0])} }
func (self Instance) AsViewport() Instance       { return Instance{pointers.AsA[gdclass.Viewport](self[0])} }
func (self *Extension[T]) AsViewport() Instance  { return self.Super().AsViewport() }
func (self class) AsNode() Node.Advanced         { return Node.Advanced{pointers.AsA[gdclass.Node](self[0])} }
func (self *Extension[T]) AsNode() Node.Instance { return self.Super().AsNode() }
func (self Instance) AsNode() Node.Instance {
	return Node.Instance{pointers.AsA[gdclass.Node](self[0])}
}

func (self class) Virtual(name string) reflect.Value {
	switch name {
	default:
		return gd.VirtualByName(Node.Advanced(self.AsNode()), name)
	}
}

func (self Instance) Virtual(name string) reflect.Value {
	switch name {
	default:
		return gd.VirtualByName(Node.Instance(self.AsNode()), name)
	}
}
func init() {
	gdclass.Register("Viewport", func(ptr gd.Object) any { return Instance{pointers.AsA[gdclass.Viewport](ptr)} })
}

type PositionalShadowAtlasQuadrantSubdiv int //gd:Viewport.PositionalShadowAtlasQuadrantSubdiv

const (
	// This quadrant will not be used.
	ShadowAtlasQuadrantSubdivDisabled PositionalShadowAtlasQuadrantSubdiv = 0
	// This quadrant will only be used by one shadow map.
	ShadowAtlasQuadrantSubdiv1 PositionalShadowAtlasQuadrantSubdiv = 1
	// This quadrant will be split in 4 and used by up to 4 shadow maps.
	ShadowAtlasQuadrantSubdiv4 PositionalShadowAtlasQuadrantSubdiv = 2
	// This quadrant will be split 16 ways and used by up to 16 shadow maps.
	ShadowAtlasQuadrantSubdiv16 PositionalShadowAtlasQuadrantSubdiv = 3
	// This quadrant will be split 64 ways and used by up to 64 shadow maps.
	ShadowAtlasQuadrantSubdiv64 PositionalShadowAtlasQuadrantSubdiv = 4
	// This quadrant will be split 256 ways and used by up to 256 shadow maps. Unless the [PositionalShadowAtlasSize] is very high, the shadows in this quadrant will be very low resolution.
	//
	// [PositionalShadowAtlasSize]: https://pkg.go.dev/graphics.gd/classdb/#Instance.PositionalShadowAtlasSize
	ShadowAtlasQuadrantSubdiv256 PositionalShadowAtlasQuadrantSubdiv = 5
	// This quadrant will be split 1024 ways and used by up to 1024 shadow maps. Unless the [PositionalShadowAtlasSize] is very high, the shadows in this quadrant will be very low resolution.
	//
	// [PositionalShadowAtlasSize]: https://pkg.go.dev/graphics.gd/classdb/#Instance.PositionalShadowAtlasSize
	ShadowAtlasQuadrantSubdiv1024 PositionalShadowAtlasQuadrantSubdiv = 6
	// Represents the size of the [PositionalShadowAtlasQuadrantSubdiv] enum.
	ShadowAtlasQuadrantSubdivMax PositionalShadowAtlasQuadrantSubdiv = 7
)

type Scaling3DMode int //gd:Viewport.Scaling3DMode

const (
	// Use bilinear scaling for the viewport's 3D buffer. The amount of scaling can be set using [Scaling3dScale]. Values less than 1.0 will result in undersampling while values greater than 1.0 will result in supersampling. A value of 1.0 disables scaling.
	//
	// [Scaling3dScale]: https://pkg.go.dev/graphics.gd/classdb/#Instance.Scaling3dScale
	Scaling3dModeBilinear Scaling3DMode = 0
	// Use AMD FidelityFX Super Resolution 1.0 upscaling for the viewport's 3D buffer. The amount of scaling can be set using [Scaling3dScale]. Values less than 1.0 will result in the viewport being upscaled using FSR. Values greater than 1.0 are not supported and bilinear downsampling will be used instead. A value of 1.0 disables scaling.
	//
	// [Scaling3dScale]: https://pkg.go.dev/graphics.gd/classdb/#Instance.Scaling3dScale
	Scaling3dModeFsr Scaling3DMode = 1
	// Use AMD FidelityFX Super Resolution 2.2 upscaling for the viewport's 3D buffer. The amount of scaling can be set using [Viewport.Scaling3dScale]. Values less than 1.0 will result in the viewport being upscaled using FSR2. Values greater than 1.0 are not supported and bilinear downsampling will be used instead. A value of 1.0 will use FSR2 at native resolution as a TAA solution.
	//
	// [Viewport.Scaling3dScale]: https://pkg.go.dev/graphics.gd/classdb/Viewport#Instance.Scaling3dScale
	Scaling3dModeFsr2 Scaling3DMode = 2
	// Use the [MetalFX spatial upscaler] for the viewport's 3D buffer.
	//
	// The amount of scaling can be set using [Scaling3dScale].
	//
	// Values less than 1.0 will result in the viewport being upscaled using MetalFX. Values greater than 1.0 are not supported and bilinear downsampling will be used instead. A value of 1.0 disables scaling.
	//
	// More information: [MetalFX].
	//
	// Note: Only supported when the Metal rendering driver is in use, which limits this scaling mode to macOS and iOS.
	//
	// [MetalFX]: https://developer.apple.com/documentation/metalfx
	// [MetalFX spatial upscaler]: https://developer.apple.com/documentation/metalfx/mtlfxspatialscaler#overview
	// [Scaling3dScale]: https://pkg.go.dev/graphics.gd/classdb/#Instance.Scaling3dScale
	Scaling3dModeMetalfxSpatial Scaling3DMode = 3
	// Use the [MetalFX temporal upscaler] for the viewport's 3D buffer.
	//
	// The amount of scaling can be set using [Scaling3dScale]. To determine the minimum input scale, use the [RenderingDevice.LimitGet] method with [Renderingdevice.LimitMetalfxTemporalScalerMinScale].
	//
	// Values less than 1.0 will result in the viewport being upscaled using MetalFX. Values greater than 1.0 are not supported and bilinear downsampling will be used instead. A value of 1.0 will use MetalFX at native resolution as a TAA solution.
	//
	// More information: [MetalFX].
	//
	// Note: Only supported when the Metal rendering driver is in use, which limits this scaling mode to macOS and iOS.
	//
	// [MetalFX]: https://developer.apple.com/documentation/metalfx
	// [MetalFX temporal upscaler]: https://developer.apple.com/documentation/metalfx/mtlfxtemporalscaler#overview
	// [RenderingDevice.LimitGet]: https://pkg.go.dev/graphics.gd/classdb/RenderingDevice#Instance.LimitGet
	// [Scaling3dScale]: https://pkg.go.dev/graphics.gd/classdb/#Instance.Scaling3dScale
	Scaling3dModeMetalfxTemporal Scaling3DMode = 4
	// Represents the size of the [Scaling3DMode] enum.
	Scaling3dModeMax Scaling3DMode = 5
)

type MSAA int //gd:Viewport.MSAA

const (
	// Multisample antialiasing mode disabled. This is the default value, and is also the fastest setting.
	MsaaDisabled MSAA = 0
	// Use 2× Multisample Antialiasing. This has a moderate performance cost. It helps reduce aliasing noticeably, but 4× MSAA still looks substantially better.
	Msaa2x MSAA = 1
	// Use 4× Multisample Antialiasing. This has a significant performance cost, and is generally a good compromise between performance and quality.
	Msaa4x MSAA = 2
	// Use 8× Multisample Antialiasing. This has a very high performance cost. The difference between 4× and 8× MSAA may not always be visible in real gameplay conditions. Likely unsupported on low-end and older hardware.
	Msaa8x MSAA = 3
	// Represents the size of the [MSAA] enum.
	MsaaMax MSAA = 4
)

type AnisotropicFiltering int //gd:Viewport.AnisotropicFiltering

const (
	// Anisotropic filtering is disabled.
	AnisotropyDisabled AnisotropicFiltering = 0
	// Use 2× anisotropic filtering.
	Anisotropy2x AnisotropicFiltering = 1
	// Use 4× anisotropic filtering. This is the default value.
	Anisotropy4x AnisotropicFiltering = 2
	// Use 8× anisotropic filtering.
	Anisotropy8x AnisotropicFiltering = 3
	// Use 16× anisotropic filtering.
	Anisotropy16x AnisotropicFiltering = 4
	// Represents the size of the [AnisotropicFiltering] enum.
	AnisotropyMax AnisotropicFiltering = 5
)

type ScreenSpaceAA int //gd:Viewport.ScreenSpaceAA

const (
	// Do not perform any antialiasing in the full screen post-process.
	ScreenSpaceAaDisabled ScreenSpaceAA = 0
	// Use fast approximate antialiasing. FXAA is a popular screen-space antialiasing method, which is fast but will make the image look blurry, especially at lower resolutions. It can still work relatively well at large resolutions such as 1440p and 4K.
	ScreenSpaceAaFxaa ScreenSpaceAA = 1
	// Use subpixel morphological antialiasing. SMAA may produce clearer results than FXAA, but at a slightly higher performance cost.
	ScreenSpaceAaSmaa ScreenSpaceAA = 2
	// Represents the size of the [ScreenSpaceAA] enum.
	ScreenSpaceAaMax ScreenSpaceAA = 3
)

